import{_ as a,c as r,o as t,aj as o}from"./chunks/framework.BlveriQe.js";const p=JSON.parse('{"title":"Interface: ResourceMetadataAPI","description":"","frontmatter":{},"headers":[],"relativePath":"reference/js-bao-wss-client/api/interfaces/ResourceMetadataAPI.md","filePath":"reference/js-bao-wss-client/api/interfaces/ResourceMetadataAPI.md"}'),s={name:"reference/js-bao-wss-client/api/interfaces/ResourceMetadataAPI.md"};function c(d,e,i,l,n,h){return t(),r("div",null,[...e[0]||(e[0]=[o('<p><a href="./../README.html"><strong>js-bao-wss-client</strong></a></p><hr><p><a href="./../globals.html">js-bao-wss-client</a> / ResourceMetadataAPI</p><h1 id="interface-resourcemetadataapi" tabindex="-1">Interface: ResourceMetadataAPI <a class="header-anchor" href="#interface-resourcemetadataapi" aria-label="Permalink to “Interface: ResourceMetadataAPI”">​</a></h1><p>Sub-API for reading and writing typed resource metadata (values only — category definitions are managed by app admins, not through this client). Reads are gated per category by its <code>readRule</code> and writes by its <code>writeRule</code>, with an app-level owner/admin bypass; a resource-level permission never bypasses. A denial surfaces as an HTTP 403 error on the single calls and as a per-item <code>ok: false</code> entry in the batch.</p><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to “Methods”">​</a></h2><h3 id="delete" tabindex="-1">delete() <a class="header-anchor" href="#delete" aria-label="Permalink to “delete()”">​</a></h3><blockquote><p><strong>delete</strong>(<code>resourceType</code>, <code>resourceId</code>, <code>category</code>): <code>Promise</code>&lt;<a href="./ResourceMetadataDeleteResult.html"><code>ResourceMetadataDeleteResult</code></a>&gt;</p></blockquote><p>Delete one resource&#39;s metadata for one category. The category&#39;s <code>writeRule</code> gates the delete (403 on denial). Idempotent: deleting an item that does not exist succeeds with <code>deleted: false</code> rather than failing with 404.</p><h4 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="resourcetype" tabindex="-1">resourceType <a class="header-anchor" href="#resourcetype" aria-label="Permalink to “resourceType”">​</a></h5><p><code>string</code></p><h5 id="resourceid" tabindex="-1">resourceId <a class="header-anchor" href="#resourceid" aria-label="Permalink to “resourceId”">​</a></h5><p><code>string</code></p><h5 id="category" tabindex="-1">category <a class="header-anchor" href="#category" aria-label="Permalink to “category”">​</a></h5><p><code>string</code></p><h4 id="returns" tabindex="-1">Returns <a class="header-anchor" href="#returns" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./ResourceMetadataDeleteResult.html"><code>ResourceMetadataDeleteResult</code></a>&gt;</p><hr><h3 id="get" tabindex="-1">get() <a class="header-anchor" href="#get" aria-label="Permalink to “get()”">​</a></h3><blockquote><p><strong>get</strong>(<code>resourceType</code>, <code>resourceId</code>, <code>category</code>): <code>Promise</code>&lt;<a href="./ResourceMetadataReadResult.html"><code>ResourceMetadataReadResult</code></a>&gt;</p></blockquote><p>Read one resource&#39;s metadata for one category. Succeeds with <code>exists: false</code> and empty <code>data</code> when nothing has been written yet; fails with 404 when the category is not defined for the resource type, or 403 when the category&#39;s <code>readRule</code> denies the caller.</p><h4 id="parameters-1" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-1" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="resourcetype-1" tabindex="-1">resourceType <a class="header-anchor" href="#resourcetype-1" aria-label="Permalink to “resourceType”">​</a></h5><p><code>string</code></p><h5 id="resourceid-1" tabindex="-1">resourceId <a class="header-anchor" href="#resourceid-1" aria-label="Permalink to “resourceId”">​</a></h5><p><code>string</code></p><h5 id="category-1" tabindex="-1">category <a class="header-anchor" href="#category-1" aria-label="Permalink to “category”">​</a></h5><p><code>string</code></p><h4 id="returns-1" tabindex="-1">Returns <a class="header-anchor" href="#returns-1" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./ResourceMetadataReadResult.html"><code>ResourceMetadataReadResult</code></a>&gt;</p><hr><h3 id="getbatch" tabindex="-1">getBatch() <a class="header-anchor" href="#getbatch" aria-label="Permalink to “getBatch()”">​</a></h3><blockquote><p><strong>getBatch</strong>(<code>params</code>): <code>Promise</code>&lt;<a href="./ResourceMetadataBatchResult.html"><code>ResourceMetadataBatchResult</code></a>&gt;</p></blockquote><p>Read metadata for many resources in one call (bounded: 50 resources / 200 resource-category pairs). Partial success: per-item 403/404 errors are returned as structured entries and do not fail the call.</p><h4 id="parameters-2" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-2" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="params" tabindex="-1">params <a class="header-anchor" href="#params" aria-label="Permalink to “params”">​</a></h5><p><a href="./ResourceMetadataBatchParams.html"><code>ResourceMetadataBatchParams</code></a></p><h4 id="returns-2" tabindex="-1">Returns <a class="header-anchor" href="#returns-2" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./ResourceMetadataBatchResult.html"><code>ResourceMetadataBatchResult</code></a>&gt;</p><hr><h3 id="list" tabindex="-1">list() <a class="header-anchor" href="#list" aria-label="Permalink to “list()”">​</a></h3><blockquote><p><strong>list</strong>(<code>resourceType</code>, <code>resourceId</code>): <code>Promise</code>&lt;<a href="./ResourceMetadataListResult.html"><code>ResourceMetadataListResult</code></a>&gt;</p></blockquote><p>List every stored metadata category on one resource. Only categories the caller may read are returned (each gated by its <code>readRule</code>, with the app-level owner/admin bypass); a resource with no metadata comes back with an empty <code>categories</code> array.</p><h4 id="parameters-3" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-3" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="resourcetype-2" tabindex="-1">resourceType <a class="header-anchor" href="#resourcetype-2" aria-label="Permalink to “resourceType”">​</a></h5><p><code>string</code></p><h5 id="resourceid-2" tabindex="-1">resourceId <a class="header-anchor" href="#resourceid-2" aria-label="Permalink to “resourceId”">​</a></h5><p><code>string</code></p><h4 id="returns-3" tabindex="-1">Returns <a class="header-anchor" href="#returns-3" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./ResourceMetadataListResult.html"><code>ResourceMetadataListResult</code></a>&gt;</p><hr><h3 id="set" tabindex="-1">set() <a class="header-anchor" href="#set" aria-label="Permalink to “set()”">​</a></h3><blockquote><p><strong>set</strong>(<code>resourceType</code>, <code>resourceId</code>, <code>category</code>, <code>data</code>): <code>Promise</code>&lt;<a href="./ResourceMetadataWriteResult.html"><code>ResourceMetadataWriteResult</code></a>&gt;</p></blockquote><p>Write (full replace) one resource&#39;s metadata for one category. The data is validated against the category&#39;s schema; the category&#39;s <code>writeRule</code> gates the write (403 on denial).</p><h4 id="parameters-4" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-4" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="resourcetype-3" tabindex="-1">resourceType <a class="header-anchor" href="#resourcetype-3" aria-label="Permalink to “resourceType”">​</a></h5><p><code>string</code></p><h5 id="resourceid-3" tabindex="-1">resourceId <a class="header-anchor" href="#resourceid-3" aria-label="Permalink to “resourceId”">​</a></h5><p><code>string</code></p><h5 id="category-2" tabindex="-1">category <a class="header-anchor" href="#category-2" aria-label="Permalink to “category”">​</a></h5><p><code>string</code></p><h5 id="data" tabindex="-1">data <a class="header-anchor" href="#data" aria-label="Permalink to “data”">​</a></h5><p><code>Record</code>&lt;<code>string</code>, <code>unknown</code>&gt;</p><h4 id="returns-4" tabindex="-1">Returns <a class="header-anchor" href="#returns-4" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./ResourceMetadataWriteResult.html"><code>ResourceMetadataWriteResult</code></a>&gt;</p>',66)])])}const m=a(s,[["render",c]]);export{p as __pageData,m as default};
